import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const navItems = [
  { path: '/dashboard', icon: '📊', label: 'Dashboard' },
  { path: '/leads', icon: '📋', label: 'Leads' },
  { path: '/properties', icon: '🏢', label: 'Properties' },
  { path: '/clients', icon: '👥', label: 'Clients' },
  { path: '/deals', icon: '🤝', label: 'Deals' },
];

export default function Sidebar() {
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <div style={styles.sidebar}>
      <div style={styles.logo}>🏠 RealEstate CRM</div>
      <div style={styles.userBadge}>
        <div style={styles.avatar}>{user?.name?.[0]?.toUpperCase()}</div>
        <div>
          <div style={styles.userName}>{user?.name}</div>
          <div style={styles.userRole}>{user?.role}</div>
        </div>
      </div>
      <nav style={styles.nav}>
        {navItems.map(item => (
          <Link key={item.path} to={item.path} style={{
            ...styles.navItem,
            ...(location.pathname === item.path ? styles.activeNavItem : {})
          }}>
            <span>{item.icon}</span>
            <span>{item.label}</span>
          </Link>
        ))}
      </nav>
      <button onClick={handleLogout} style={styles.logoutBtn}>🚪 Logout</button>
    </div>
  );
}

const styles = {
  sidebar: { width:'220px', minHeight:'100vh', background:'#1e293b', color:'#e2e8f0', display:'flex', flexDirection:'column', padding:'20px 0', position:'fixed', top:0, left:0 },
  logo: { fontSize:'16px', fontWeight:'700', color:'#38bdf8', padding:'0 20px 20px', borderBottom:'1px solid #334155' },
  userBadge: { display:'flex', alignItems:'center', gap:'10px', padding:'16px 20px', borderBottom:'1px solid #334155' },
  avatar: { width:'36px', height:'36px', borderRadius:'50%', background:'#3b82f6', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:'700', fontSize:'16px' },
  userName: { fontSize:'13px', fontWeight:'600' },
  userRole: { fontSize:'11px', color:'#94a3b8', textTransform:'capitalize' },
  nav: { flex:1, padding:'16px 12px', display:'flex', flexDirection:'column', gap:'4px' },
  navItem: { display:'flex', alignItems:'center', gap:'10px', padding:'10px 12px', borderRadius:'8px', color:'#94a3b8', textDecoration:'none', fontSize:'14px', transition:'all 0.2s' },
  activeNavItem: { background:'#3b82f6', color:'#fff' },
  logoutBtn: { margin:'0 12px 12px', padding:'10px', background:'#334155', color:'#e2e8f0', border:'none', borderRadius:'8px', cursor:'pointer', fontSize:'13px', textAlign:'left' }
};
